import React, { useState } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function SugarMonitor(){
    const [beforeMeal,setBeforeMeal]=useState("");
    const [afterMeal,setAfterMeal]=useState("");

    const navigate=useNavigate();
        

        async function handleSubmit(e) {
            e.preventDefault();
            if(!beforeMeal || !afterMeal){
                alert("Please fill all the inputs");
            }
            try{
                const response=await fetch('http://localhost:5000/sugar-level-page',
                    {
                        method:'POST',
                        headers:{'Content-Type':'application/json'},
                        body:JSON.stringify({beforeMeal,afterMeal})
                    }
                )
                const data=await response.json();
                if(data.success){
                    alert('sugar levels saved');
                    navigate('/dashboard');
                }
            }
            catch(err){
                console.log(err);
            }
            
        }

    return(
        <>
            <h1 className="l2container"> If you had a sugar test recently then enter your sugar test results </h1><br/>
            <br/>
            <form className="signcontainer">
                <br/><label htmlFor="beforeMeal">Enter Sugar Levels Before Meal:</label><br/>
                <input type="text" name="beforeMeal" id="beforeMeal" onChange={(e)=>setBeforeMeal(e.target.value)}/><br/><br/>
                <label htmlFor="afterMeal">Enter Sugar Levels Afer Meal:</label><br/>
                <input type="text" name="afterMeal" id="afterMeal" onChange={(e)=>setAfterMeal(e.target.value)}/><br/><br/>
                <button type="button" onClick={handleSubmit}>Add</button>
            </form>
        </>
        
    );
}

export default SugarMonitor;
